options.afterRender:
const panel = $('#customHolidaySchedulePanel');
const startInput = panel.find('#customScheduleStart');
const endInput = panel.find('#customScheduleEnd');
const saveButton = panel.find('.save');
const resetButton = panel.find('.reset');
const status = panel.find('.custom-holiday-status');
const initialStart = startInput.val();
const initialEnd = endInput.val();

const setStatus = (message, isError = false) => {
  status.removeClass('text-success text-danger').addClass(isError ? 'text-danger' : 'text-success').text(message);
};

const normalizeTime = (value) => {
  const text = String(value || '').trim();
  const match = text.match(/^(\d{1,2}):(\d{2})(?::(\d{2}))?$/);
  if (!match) return undefined;

  const hour = Number(match[1]);
  const minute = Number(match[2]);
  const second = match[3] === undefined ? 0 : Number(match[3]);
  if (hour > 23 || minute > 59 || second > 59) return undefined;

  return [hour, minute, second]
    .map((part) => String(part).padStart(2, '0'))
    .join(':');
};

const timeToSeconds = (time) => {
  const [hour, minute, second] = time.split(':').map(Number);
  return hour * 3600 + minute * 60 + second;
};

const validate = () => {
  const start = normalizeTime(startInput.val());
  const end = normalizeTime(endInput.val());

  startInput.toggleClass('is-invalid', !start);
  endInput.toggleClass('is-invalid', !end);

  if (!start || !end) {
    setStatus('Use a valid time in HH:mm or HH:mm:ss format.', true);
    return undefined;
  }

  if (timeToSeconds(start) >= timeToSeconds(end)) {
    startInput.addClass('is-invalid');
    endInput.addClass('is-invalid');
    setStatus('Start time must be before end time.', true);
    return undefined;
  }

  startInput.removeClass('is-invalid');
  endInput.removeClass('is-invalid');
  return { start, end };
};

const parseBody = async (response) => {
  const text = await response.text();
  if (!text) return undefined;
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

const errorMessage = (response, body) => {
  if (typeof body === 'string') return body || 'HTTP ' + response.status;
  if (body && body.error) return body.error;
  return 'HTTP ' + response.status;
};

const updateParams = async (values) => {
  const response = await fetch('/cpms/params/global', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      values,
      reason: 'Update custom holiday schedule time from Grafana',
    }),
  });
  const body = await parseBody(response);

  if (!response.ok) {
    throw new Error(errorMessage(response, body) + ' (' + response.status + ')');
  }
};

startInput.add(endInput).off('input').on('input', () => {
  status.removeClass('text-success text-danger').text('');
  startInput.removeClass('is-invalid');
  endInput.removeClass('is-invalid');
});

resetButton.off('click').on('click', () => {
  startInput.val(initialStart).removeClass('is-invalid');
  endInput.val(initialEnd).removeClass('is-invalid');
  status.removeClass('text-success text-danger').text('');
});

saveButton.off('click').on('click', async () => {
  const values = validate();
  if (!values) return;

  saveButton.prop('disabled', true).text('Updating...');
  resetButton.prop('disabled', true);
  startInput.prop('disabled', true);
  endInput.prop('disabled', true);
  status.removeClass('text-success text-danger').text('Updating custom holiday schedule...');

  try {
    await updateParams({
      'schedule.start_time': values.start,
      'schedule.end_time': values.end,
    });
    startInput.val(values.start);
    endInput.val(values.end);
    setStatus('Custom holiday schedule updated.');
    context.grafana.notifySuccess(['Custom holiday schedule updated.']);
    setTimeout(() => context.grafana.refresh(), 1000);
  } catch (error) {
    setStatus('Update failed: ' + error.message, true);
    context.grafana.notifyError(['Error', 'Update failed: ' + error.message]);
  } finally {
    saveButton.prop('disabled', false).text('Update');
    resetButton.prop('disabled', false);
    startInput.prop('disabled', false);
    endInput.prop('disabled', false);
  }
});

var id = new Date().valueOf();
window.pmpCheckIntervalId = id;
function checkError() {
  if (id !== window.pmpCheckIntervalId) return;
  if (window.location.pathname !== "/d/adfvzm4/chiller-schedules") return;

  const ele = $('div[data-testid*="error-alert-element"]');
  if (ele.length > 0) {
    const errText = ele.find('div:contains("status code")').filter(function () { return $(this).children().length === 0 });
    if (errText.length > 0) {  
      if (errText.text().indexOf('409 Conflict') > -1) {
        errText.text('Duplicate holiday date');
      }
    }
  }
  setTimeout(checkError, 100);
}
checkError();
